// // This T-flip-flop toggles its output (Q) on every falling edge of the clock when the T input is high.
module T_flip_flop (  
    input wire T,  
    input wire CLK,  
    input wire RST,  
    output reg Q  
);  
    always @(posedge CLK or posedge RST) begin  
        if (RST)  
            Q <= 0;  
        else if (T)  
            Q <= ~Q;  
    end  
endmodule
